import{_ as i,p as l,q as e,a1 as t}from"./framework-96b046e1.js";const _={},a=t('<p>这篇文章就来总结下<strong>单片机</strong>开发相关的东西把，主要就是总结下单片机开发中常用的模块以及常用的驱动开发有哪些。</p><h2 id="单片机开发必备" tabindex="-1"><a class="header-anchor" href="#单片机开发必备" aria-hidden="true">#</a> 单片机开发必备</h2><ol><li>按键功能（按键是每个单片机系统中必不可少的，所以对于按键的程序编写必须熟悉）</li><li>LED灯（LED灯的驱动也是必不可少的，LED 灯可以显示当前设备的工作状态）</li><li>屏幕（数码管、OLED、TFT、液晶屏、串口屏等）</li><li>蜂鸣器</li><li>继电器驱动</li><li>电机控制（直流电机，电机速度控制，电机启停控制，电机闭环控制等）</li><li>光敏传感器 (光敏电阻、光敏二极管、光敏三极管等)</li><li>温度传感器（K型热电偶，PT100热敏电阻，DS18B20等）</li><li>湿度传感器</li><li>光照传感器</li><li>红外传感器</li><li>编码器</li><li>气体传感器（可燃传感器、毒气传感器等）</li><li>压力传感器（气压传感器，液压传感器，压力传感器）</li><li>磁敏传感器</li><li></li></ol>',3),o=[a];function r(c,n){return l(),e("div",null,o)}const d=i(_,[["render",r],["__file","单片机开发总结.html.vue"]]);export{d as default};
